@@ -3630,9 +3630,15 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
               : (match(FV, m_Zero()) && isKnownNonZero(TV, Q))) {
         Value *Cmp = Builder.CreateICmp(
             Pred, Other, Constant::getNullValue(Other->getType()));
+        Value *CondToUse = Cond;
+        // If Cmp is a vector type but Cond is scalar, splat Cond to match.
+        if (Cmp->getType()->isVectorTy() && !Cond->getType()->isVectorTy()) {
+          CondToUse = Builder.CreateVectorSplat(
+              cast<VectorType>(Cmp->getType())->getElementCount(), Cond);
+        }
         return BinaryOperator::Create(
             Pred == ICmpInst::ICMP_EQ ? Instruction::And : Instruction::Or, Cmp,
-            Cond);
+            CondToUse);
       }
       // Harder case is if eq/ne matches whether 0 is falseval/trueval. In this
       // case we need to invert the select condition so we need to be careful to
@@ -3653,9 +3659,15 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         Value *NotCond = Builder.CreateNot(Cond);
         Value *Cmp = Builder.CreateICmp(
             Pred, Other, Constant::getNullValue(Other->getType()));
+        Value *NotCondToUse = NotCond;
+        // If Cmp is a vector type but NotCond is scalar, splat NotCond to match.
+        if (Cmp->getType()->isVectorTy() && !NotCond->getType()->isVectorTy()) {
+          NotCondToUse = Builder.CreateVectorSplat(
+              cast<VectorType>(Cmp->getType())->getElementCount(), NotCond);
+        }
         return BinaryOperator::Create(
             Pred == ICmpInst::ICMP_EQ ? Instruction::And : Instruction::Or, Cmp,
-            NotCond);
+            NotCondToUse);
       }
     }
     break;
